arguments.command:
# Find the exact thunk symbols containing each address
nm -n /tmp/mono_debug.dbg 2>/dev/null | grep -i 'CortexA53' | awk '
{
  addr = strtonum("0x"$1)
  symbols[NR] = $0
  addrs[NR] = addr
}
END {
  # Find symbol containing 0x2f4b20
  target1 = strtonum("0x2f4b20")
  target2 = strtonum("0x2f4c84")
  best1 = ""; best2 = ""
  for (i = 1; i <= NR; i++) {
    if (addrs[i] <= target1) best1 = symbols[i]
    if (addrs[i] <= target2) best2 = symbols[i]
  }
  print "0x2f4b20 => " best1
  print "0x2f4c84 => " best2
}'

