nm -n /tmp/mono_debug.dbg 2>/dev/null | grep ' [tT] ' | grep -v '^\$' | grep -v '__Cortex' | grep -v '__aarch64' | awk '
{
  addr = strtonum("0x"$1)
  if (addr <= strtonum("0x2f4b20")) { sym1_addr=$1; sym1_name=$3 }
  if (addr <= strtonum("0x2f4c84")) { sym2_addr=$1; sym2_name=$3 }
}
END {
  print "Nearest function to 0x2f4b20: " sym1_name " at 0x" sym1_addr
  print "Nearest function to 0x2f4c84: " sym2_name " at 0x" sym2_addr
}'

